def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            if capacity == 0 and item == 0:
                priorities[i] = 0.0
            else:
                priorities[i] = np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        penalty = 0.0
        extra_bonus = 0.0
        if item == 0:
            priorities[i] = 0.0
            continue
        if ratio > 4:
            for k in range(1, 8):
                penalty += (ratio ** (4 * k)) / (k ** 4 + 2*k)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j + 3)) ** (1/j)
            score = (ratio ** 6) / 3 + penalty * 0.8
            if item > capacity * 5:
                score *= 4
            else:
                score *= 2.5
            priorities[i] = score * decay
        elif 3 < ratio <= 4:
            for x in range(1, 10):
                sign = (-1) ** (x + 1)
                score += sign * (ratio ** x) / (2*x + 1)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 4)) ** 1.1
            score = abs(score) * decay * 18
            priorities[i] = score
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 7)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 5)
                else:
                    temp += (ratio ** p) / (p * 4)
            multiplier = 30 if ratio < 2.3 else 20 if ratio < 2.7 else 12
            score = abs(temp) * multiplier
            if ratio > 2.8:
                extra = 0
                for m in range(1, 8):
                    extra += (ratio ** m) / (m + 2)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            for p in range(1, 20):
                if p % 5 == 0:
                    temp_score += (ratio ** p) / (p * 4)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * 6)
                else:
                    temp_score += (ratio ** p) / (p * 5)
            if ratio < 1.25:
                multiplier = 40
            elif ratio < 1.5:
                multiplier = 28
            elif ratio < 1.75:
                multiplier = 18
            else:
                multiplier = 12
            score = abs(temp_score) * multiplier
            if ratio > 1.9:
                extra_bonus = 0
                for n in range(1, 10):
                    extra_bonus += (ratio ** n) / (n + 2)
                score += extra_bonus * 2.5
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp = 0
            for p in range(1, 20):
                if p % 6 == 0:
                    temp += (ratio ** p) / (p * 5)
                elif p % 4 == 0:
                    temp -= (ratio ** p) / (p * 8)
                elif p % 3 == 0:
                    temp += (ratio ** p) / (p * 10)
                else:
                    temp -= (ratio ** p) / (p * 7)
            if ratio < 0.15:
                multiplier = 35
            elif ratio < 0.35:
                multiplier = 25
            elif ratio < 0.55:
                multiplier = 18
            elif ratio < 0.75:
                multiplier = 10
            else:
                multiplier = 7
            score = abs(temp) * multiplier
            if 0.8 < ratio <= 1:
                extra_penalty = 0
                for q in range(1, 10):
                    extra_penalty += (ratio ** q) / (q + 3)
                score += extra_penalty * 3
            priorities[i] = score
        else:
            priorities[i] = np.inf
        if priorities[i] != np.inf:
            factor1 = 1.0
            for z in range(1, 5):
                factor1 *= (1 + z / (bins[i] + 2))
            factor2 = 1.0
            for w in range(1, 3):
                if item > 0:
                    factor2 *= (1 + np.log1p(item) / (w + bins[i]))
            priority_val = priorities[i] * factor1 * factor2
            if item > capacity:
                priority_val += np.sqrt(item) / (capacity + 1)
            priorities[i] = priority_val
    return priorities
